{
  "title": "Sous-requête corrélée",
  "group": "Sous-requêtes SQL",
  "options": [
    {
      "text": "Une sous-requête qui s'exécute une seule fois au total"
    },
    {
      "text": "Une sous-requête utilisée uniquement dans les instructions JOIN"
    },
    {
      "text": "Une sous-requête qui retourne uniquement plusieurs colonnes"
    },
    {
      "text": "Une sous-requête qui s'exécute une fois pour chaque ligne de la requête externe"
    }
  ],
  "questionProse": [
    "Qu'est-ce qu'une sous-requête corrélée en SQL ?"
  ],
  "explanationProse": [
    "Une sous-requête corrélée est évaluée une fois par ligne de la requête externe. Elle fait référence à des colonnes de la requête externe, ce qui la rend dépendante de chaque ligne."
  ]
}
